oldWay:
/* Hard-coded line numbers — breaks when column count changes */
.featured {
  grid-column: 1 / 3;
  grid-row: 1;
}
/* Must update numbers whenever the grid definition changes */

startingCSS:
.grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 0.75rem;
}

.card {
  background: #1e293b;
  border: 1px solid #334155;
  padding: 1.25rem;
  border-radius: 8px;
  color: #e2e8f0;
  font-weight: 500;
  font-size: 0.9rem;
}

.featured {
  background: #7c3aed;
  border-color: #a855f7;
  color: white;
  /* Make this span two columns */
}

alternatives.css:
.featured {
  grid-column: 1 / 3; /* start at line 1, end at line 3 */
}
